  ('bookkeeper-moex-00879', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行所得稅法規定，個人居住者因財政部公告之調職、非自願離職或其他非自願性因素，交易於 105 年後購入、持有期間在二年以下之房屋、土地者，該交易之所得稅稅率為多少？', '["15%", "20%", "35%", "45%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00880', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行所得稅法規定，個人非居住者交易於 105 年後購入、持有房屋、土地之期間超過十年者，該交易 之所得稅稅率為多少？', '["15%", "20%", "35%", "45%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00881', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行所得稅法規定，個人居住者107年度之下列何種所得應採分離課稅，無須計入綜合所得總額？', '["公司債之利息", "檢舉逃漏稅之獎金", "統一發票之中獎獎金", "104年以前購入之房屋之出售所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00882', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營業稅法相關規定，有關銷售額之敘述，下列何者錯誤？', '["互易貨物應以換入或換出時價從高認定", "銷售額應包括應稅貨物之貨物稅", "以較時價為低之價格銷售而無正當理由時，稽徵機關得以時價認定其銷售額", "受託代購貨物者，其銷售額應以時價為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00883', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依遺贈稅法規定，有關分期繳納及實物抵繳之敘述，下列何者正確？', '["應納稅額須在30萬元以上", "分期繳納最多分12期", "分期繳納每期間隔不超過3個月", "得以納稅義務人所有之境內外課徵標的物抵繳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00884', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國國民王先生（居住者，無配偶）107年中因病去世，遺有國內銀行存款7,000萬元、國外銀行存款2,000 萬元，由獨生女（17歲3個月）繼承遺產。請問其遺產稅應納稅額為多少元？', '["5,715,500元", "8,715,500元", "8,790,500元", "8,975,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00885', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '107年度黃先生取得境外來源所得80萬元，黃太太取得境外來源所得1,000萬元。該申報戶之綜合所得 總額為700萬元、綜合所得淨額為650萬元。請問該申報戶之基本所得稅額為多少元？', '["196萬元", "202萬元", "212萬元", "222萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00886', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '北宸公司經營製造業，106年1月1日購置乘人小客車一輛供公務使用，購入成本為400萬元，殘值50萬 元，耐用年限5年，採直線法提列折舊。請問其106年度依所得稅法規定，可認列之折舊費用為多少元？', '["262,500元", "400,000元", "437,500元", "500,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00887', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '中宸公司帳列營業毛利5,000萬元，營業費用3,000萬元，非營業損失200萬元。營業費用中包括對公立 大學捐贈300萬元及直接對私立大學捐贈400萬元。請問該公司依所得稅法規定，全年可認列之捐贈費 用為多少元？', '["4,636,363元", "5,000,000元", "6,200,000元", "7,400,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00888', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '小宸公司經會計師查核簽證申報，本年度全年銷貨收入 2,000 萬元（內含已取得外匯之外銷收入 500 萬 元），進貨成本1,000萬元。其依所得稅法規定，可認列之交際費上限為多少元？（提示：以銷貨為目的， 全年銷貨貨價在3,000萬元以下者，以不超過全年銷貨貨價4.5‰為限；經核准使用藍色申報書者，以不 超過全年銷貨貨價6‰為限。以進貨為目的，全年進貨貨價在3,000萬元以下者，以不超過全年進貨貨價', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00889', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '5‰為限；經核准使用藍色申報書者，以不超過全年進貨貨價2‰為限。）', '["240,000元", "210,000元", "205,000元", "182,500元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00890', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '納稅義務人黃小姐有兩戶自用房產，107年度之房屋貸款利息支出分別為15萬元與25萬元，同年亦有銀 行利息收入20萬元，均取具合法憑證。依所得稅法規定，黃小姐至多得申報之購屋借款利息扣除額為多 少元？', '["5萬元", "20萬元", "30萬元", "40萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00891', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，納稅義務人扶養之下列親屬或家屬，何者不得自其綜合所得總額減除免稅額？', '["年滿70歲以上之姑姑", "未滿60歲但失業無工作收入之岳父", "年滿20歲待業中無工作收入之弟弟", "年滿20歲在國外就讀大學（經教育部認可、具正式學籍）之子女"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00892', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '總機構設於我國境內之大宸公司，107年以1,200萬元出售其於105年以1,100萬元購入之房地產，用以 計算土地增值稅之土地漲價總數額為60萬元，應納土地增值稅為20萬元，交易仲介費50萬元，無其他 費用。依所得稅法規定，該筆交易應如何計入營利事業所得額？', '["以零計入", "虧損10萬元", "虧損20萬元", "虧損30萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00893', 'bookkeeper', 'bookkeeper-moex-107-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法規定，有關個人申請房地合一所得稅重購退稅之敘述，下列何者錯誤？', '["自完成移轉登記之日起算二年內，重購自住房屋、土地", "於重購自住房屋、土地完成移轉登記次日起算五年內，申請退還", "按重購價額與出售價額之差額，自已繳稅額計算退還", "重購之自住房屋、土地，於重購後五年內改作其他用途或再行移轉時，應追繳原退還稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:25+00:00", "source_pdf_sha1": "4a020fb6864b", "answer_pdf_sha1": "188805b3360a", "source_family": "moex-gov-tw", "moex": {"exam_code": "107180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "107", "exam_name": "107年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
